const fs = require('fs');
const path = require('path');

const API_KEY = process.env.PREMBLY_API_KEY;
const API_URL = 'https://api.prembly.com/api/v1/checker-widget/sdk/sessions/';
const LOG_FILE = path.join(__dirname, 'output.log');

async function pollSessions() {
  if (!API_KEY) {
    console.error('Error: PREMBLY_API_KEY environment variable is not set.');
    process.exit(1);
  }

  try {
    const response = await fetch(API_URL, {
      method: 'GET',
      headers: {
        'x-api-key': API_KEY,
        'Accept': 'application/json'
      }
    });

    if (!response.ok) {
      throw new Error(`HTTP error! status: ${response.status}`);
    }

    const data = await response.json();

    // Prembly API response structure for this endpoint typically contains data in a 'data' field or directly as an array.
    // Based on requirements, we count the total number of sessions.
    let count = 0;
    if (Array.isArray(data)) {
      count = data.length;
    } else if (data && data.data && Array.isArray(data.data)) {
      count = data.data.length;
    } else if (data && typeof data === 'object') {
      // Some APIs return a total count field
      count = data.total || data.count || 0;
    }

    const logMessage = `Total sessions: ${count}\n`;
    fs.writeFileSync(LOG_FILE, logMessage);
    console.log(logMessage.trim());

  } catch (error) {
    console.error('Error fetching sessions:', error.message);
    fs.writeFileSync(LOG_FILE, `Error: ${error.message}\n`);
    process.exit(1);
  }
}

pollSessions();

